<template><section class="card"><div class="card-head"><div><p class="eyebrow">脱敏事件</p><h2>候选与工具摘要</h2></div><span class="badge">最近 {{ events.length }} 条</span></div><div class="event-list"><article v-for="event in events" :key="event.event_id"><strong>{{ event.event_type }}</strong><span>{{ event.agent_name || '-' }} · {{ event.status || '-' }} · attempt {{ event.attempt || 0 }}</span><p>{{ summary(event) }}</p><small v-if="event.tool_name">工具：{{ event.tool_name }}</small><small v-if="event.latency_ms != null">耗时：{{ event.latency_ms }}ms</small></article><p v-if="!events.length" class="muted">等待候选执行事件…</p></div></section></template>
<script setup lang="ts">export type AgentEvent={event_id:number;event_type:string;agent_name?:string;status?:string;attempt?:number;tool_name?:string;latency_ms?:number;summary?:Record<string,unknown>;evidence_refs?:unknown[]};defineProps<{events:AgentEvent[]}>();function summary(event:AgentEvent){const safe=event.summary||{};return Object.entries(safe).map(([k,v])=>`${k}: ${String(v)}`).join('；')}</script>
<style scoped>.event-list{display:grid;gap:8px;max-height:360px;overflow:auto}.event-list article{display:grid;grid-template-columns:180px 1fr;gap:5px 12px;padding:12px;border-bottom:1px solid var(--line)}.event-list p{grid-column:1/-1;margin:0;color:var(--muted)}.event-list small{color:var(--muted)}</style>
